module RefModule (
    input wire [4:0] data_in,
    input wire ack,
    input wire clk,
    output reg [4:0] data_out
);
    reg [4:0] unused_last_data;

    always @(posedge clk) begin
        if (ack) begin
            data_out <= data_in;
            unused_last_data <= data_in;
        end else begin
            data_out <= unused_last_data;
        end
    end
endmodule
